// ImGuiModule 在 Android CGO 环境下把 Lua VM 入口桥接到真实 AutoGo/imgui。
type ImGuiModule struct{}

// New 创建 imgui Lua VM 模块实例。
func New() *ImGuiModule { return &ImGuiModule{} }

// Name 返回模块名。
func (m *ImGuiModule) Name() string { return "imgui" }

// IsAvailable 返回当前构建环境下模块是否可用。
func (m *ImGuiModule) IsAvailable() bool { return true }

// Register 注册 AutoGo imgui 的真实导出方法到 Lua VM。
