// imguiReflectContextopaqueGetData 兼容无法在编译期表达的 ImGui opaque context 数据访问器。
func imguiReflectContextopaqueGetData(value interface{}) (result interface{}) {
	// 第三方对象的反射调用可能 panic，统一降级为 nil 以保护脚本引擎进程。
	defer func() {
		if recover() != nil {
			result = nil
		}
	}()
	if value == nil {
		// 空对象没有可读取的 opaque context。
		return nil
	}
	method := reflect.ValueOf(value).MethodByName("ContextopaqueGetData")
	if !method.IsValid() {
		// 当前 ImGui SDK 未提供该方法时保持向后兼容。
		return nil
	}
	results := method.Call(nil)
	if len(results) == 0 {
		// 无返回值等价于没有 context 数据。
		return nil
	}
	return results[0].Interface()
}

